ZSNAP_F01G_FISCALYEARPERIOD.@DataWarehouse.tableFunction.script:
return select
	/*@EndUserText.label: 'Fiscal Year Variant'*/
	MAIN."FiscalYearVariant" as FISCALYEARVARIANT,
	MAIN."FiscalYearPeriod" as FISCALYEARPERIOD,

	/*@EndUserText.label: 'Fiscal Year'*/
	MAIN."FiscalYear" as FISCALYEAR,

	/*@EndUserText.label: 'Fiscal Period'*/
	MAIN."FiscalPeriod" as FISCALPERIOD,

	/*@EndUserText.label: 'Fiscal Period Start Date'*/
	TO_DATE (MAIN."FiscalPeriodStartDate", 'YYYYMMDD') as FISCALPERIODSTARTDATE,

	/*@EndUserText.label: 'Fiscal Period End Date'*/
	TO_DATE (MAIN."FiscalPeriodEndDate", 'YYYYMMDD') as FISCALPERIODENDDATE,

	/*@EndUserText.label: 'Is Special Period'*/
	MAIN."IsSpecialPeriod" as ISSPECIALPERIOD,

	/*@EndUserText.label: 'Fiscal Year Start Date'*/
	TO_DATE (MAIN."FiscalYearStartDate", 'YYYYMMDD') as FISCALYEARSTARTDATE,

	/*@EndUserText.label: 'Fiscal Year End Date'*/
	TO_DATE (MAIN."FiscalYearEndDate", 'YYYYMMDD') as FISCALYEARENDDATE,

	/*@EndUserText.label: 'Fiscal Year Period (Numbering)'*/
	_FISCALCALENDARDATE.FISCALPERIODCONSECUTIVENUMBER,

	/*@EndUserText.label: 'Next Fiscal Period'*/
	MAIN."NextFiscalPeriod" as NEXTFISCALPERIOD,

	/*@EndUserText.label: 'Fiscal Year of Next Fiscal Period'*/
	MAIN."NextFiscalPeriodFiscalYear" as NEXTFISCALPERIODFISCALYEAR,
	CONCAT (MAIN."NextFiscalPeriodFiscalYear", MAIN."NextFiscalPeriod") as NEXTFISCALYEARPERIOD,

	/*@EndUserText.label: 'Fiscal Year Period (Numbering)'*/
	_FISCALCALENDARDATE.FISCALPERIODCONSECUTIVENUMBER + 1 as NEXTFSCLPERIODCONSECUTIVENMBR,

	/*@EndUserText.label: 'Fiscal Quarter'*/
	_FISCALCALENDARDATE.FISCALQUARTER,

	/*@EndUserText.label: 'Fiscal Year Quarter'*/
	_FISCALCALENDARDATE.FISCALYEARQUARTER
from I_FISCALPERIODFORVARIANT as MAIN
left outer join ZSNAP_F01G_FISCALCALENDARDATE as _FISCALCALENDARDATE on MAIN."FiscalYearVariant" = _FISCALCALENDARDATE.FISCALYEARVARIANT and MAIN."FiscalPeriodEndDate" = _FISCALCALENDARDATE.CALENDARDATE;

