ZSNAP_F01M_INTERCOMPANYPAIRING.@DataWarehouse.tableFunction.script:
return select
	/*@EndUserText.label: 'Pairing Key'
	@ObjectModel.text.element: ['Description']
	@AnalyticsDetails.query.display: #KEY_TEXT*/
	CONCAT (COALESCE (MAINCOMPANYCODE."CompanyCode", MAIN.COMPANYCODE), CONCAT ('-', COALESCE (OFFSETTINGCOMPANYCODE."CompanyCode", OFFSETTINGCOMPANY.COMPANYCODE))) as INTERCOMPANYPAIRING,

	/*@EndUserText.label: 'Description'
	@Semantics.text: true*/
	MAIN.COMPANYNAME || ' ' || '<=>' || ' ' || OFFSETTINGCOMPANY.COMPANYNAME as DESCRIPTION
from ZSNAP_F01M_P_INTERCOMPANYPAIRING as MAIN
left outer join ZSNAP_F01M_P_INTERCOMPANYPAIRING as OFFSETTINGCOMPANY on MAIN.PARTNERCOMPANY < OFFSETTINGCOMPANY.PARTNERCOMPANY and OFFSETTINGCOMPANY.LENGTHCHECK <= 4
left outer join I_COMPANYCODE as MAINCOMPANYCODE on MAINCOMPANYCODE."Company" = MAIN.PARTNERCOMPANY
left outer join I_COMPANYCODE as OFFSETTINGCOMPANYCODE on OFFSETTINGCOMPANYCODE."Company" = OFFSETTINGCOMPANY.PARTNERCOMPANY
where MAIN.LENGTHCHECK <= 4;
